/* globals console, window, document */

const dataSets = [
	{
		id: '78900',
		label: 'David Lee',
		values: {
			guestTitle: 'Mr.',
			guestName: 'David Lee',
			reservationNumber: 'Y2JKH5G1Z',
			guestArrivalDate: new Date( 2024, 7, 22 ).toLocaleDateString(),
			guestDepartureDate: new Date( 2024, 8, 22 ).toLocaleDateString(),
			numberOfGuests: 2,
			roomType: 'Double Room',
			guestPhoneNumber: '567-890-1234',
			guestDiscount: '20%'
		}
	},
	{
		id: '78901',
		label: 'Kate Smith',
		values: {
			guestTitle: 'Ms.',
			guestName: 'Kate Smith',
			reservationNumber: 'GRJKCCG23',
			guestArrivalDate: new Date( 2024, 4, 12 ).toLocaleDateString(),
			guestDepartureDate: new Date( 2024, 9, 22 ).toLocaleDateString(),
			numberOfGuests: 3,
			roomType: 'Apartment',
			guestPhoneNumber: '557-333-1234',
			guestDiscount: '30%'
		}
	}
];

const additionalMergeFieldsConfig = {
	dataSets,
	previewModes: [ '$labels', '$dataSets' ]
};

window.ClassicEditor
	.create( document.querySelector( '#snippet-merge-fields-datasets' ), {
		mergeFields: { ...window.ClassicEditor.defaultConfig.mergeFields, ...additionalMergeFieldsConfig },
		toolbar: {
			items: [ 'insertMergeField', 'previewMergeFields' ].concat( window.ClassicEditor.defaultConfig.toolbar.items )
		}
	} )
	.then( editor => {
		window.editor = editor;

		// Prevent showing a warning notification when user is pasting a content from MS Word or Google Docs.
		window.preventPasteFromOfficeNotification = true;

		window.attachTourBalloon( {
			target: window.findToolbarItem(
				editor.ui.view.toolbar, item => item.buttonView && item.buttonView.label === 'Merge fields preview'
			),
			text: 'Click to change preview mode.',
			editor,
			tippyOptions: {
				placement: 'bottom-start'
			}
		} );
	} )
	.catch( err => {
		console.error( err.stack );
	} );
